#!/usr/bin/env python3
# AUTOGENERATED - Parfums Stock Manager
import json, os, datetime, sys
D = os.path.dirname(os.path.abspath(__file__))
B = os.path.join(D, "parfums.json")
def L():
 with open(B, encoding="utf-8") as f: return json.load(f)
def S(db):
 bkp = B.replace(".json","-"+str(datetime.date.today())+".json")
 if not os.path.exists(bkp): import shutil; shutil.copy2(B, bkp)
 db["_meta"]["total_parfums"]=len(db["parfums"])
 db["_meta"]["total_stock"]=sum(p["stock"] for p in db["parfums"])
 db["_meta"]["derniere_modif"]=datetime.datetime.now().strftime("%Y-%m-%d %H:%M")
 with open(B,"w",encoding="utf-8") as f: json.dump(db,f,indent=2,ensure_ascii=False)
def A(db):
 P=db["parfums"]
 print("="*60)
 print(f"  " + db["_meta"]["titre"])
 print("="*60)
 for x in P:
  b="RUPTURE" if x["stock"]<=0 else ("Bas" if x["stock"]<=2 else "OK")
  print("  [{:>8s}] {:30s} {:25s} x{:2d}".format(b, x["marque"], x["nom"], x["stock"]))
 t=sum(x["stock"] for x in P)
 print("="*60)
 print(f"  {len(P)} parfums | {t} unites")
 r=[x for x in P if x["stock"]<=0]
 if r: print("  Ruptures:",", ".join(x["nom"] for x in r))
def set_stock(pid,val):
 db=L()
 for p in db["parfums"]:
  if p["id"]==pid: old=p["stock"]; p["stock"]=val; S(db); print(p["marque"] + "-" + p["nom"] + ": " + str(old) + "->" + str(val)); gen(); return
 print("ID " + str(pid) + " introuvable")
def add_stock(pid,qty):
 db=L()
 for p in db["parfums"]:
  if p["id"]==pid: old=p["stock"]; p["stock"]+=qty; S(db); print(p["marque"] + "-" + p["nom"] + ": " + str(old) + "->" + str(p["stock"])); gen(); return
 print("ID " + str(pid) + " introuvable")
def add_new(data):
 db=L()
 db["parfums"].append({"id":data["id"],"nom":data["nom"],"marque":data.get("marque",""),"type":data.get("type","EDP"),"ml":data.get("ml",100),"stock":data["stock"],"notes":data.get("notes",""),"categorie":data.get("categorie","Mixte")})
 S(db); print("Ajoute: " + data["marque"] + "-" + data["nom"] + " x" + str(data["stock"])); gen()

def gen():
 import json, datetime
 with open(B, encoding="utf-8") as f:
  db = json.load(f)
 P = db["parfums"]
 total = sum(p["stock"] for p in P)
 rupt = [p for p in P if p["stock"] <= 0]
 low = [p for p in P if 0 < p["stock"] <= 2]

 def card(p):
  if p["stock"] <= 0:
   badge = "<span class=\"bdg bdg-rup\">RUPTURE</span>"
   rc = " rup"
  elif p["stock"] <= 2:
   badge = "<span class=\"bdg bdg-bas\">Stock bas (" + str(p["stock"]) + ")</span>"
   rc = ""
  else:
   badge = "<span class=\"bdg bdg-ok\">" + str(p["stock"]) + " en stock</span>"
   rc = ""
  return "<div class=\"c" + rc + "\"><div class=\"c-bdg\">" + badge + "</div><div class=\"c-hd\"><span class=\"mq\">" + p["marque"] + "</span><span class=\"tp\">" + p["type"] + " &middot; " + str(p["ml"]) + "ml</span></div><div class=\"c-tl\">" + p["nom"] + "</div><div class=\"c-nt\">" + p["notes"] + "</div><div class=\"c-ft\"><span class=\"st\">" + ("x" + str(p["stock"]) if p["stock"] > 0 else "EPUISE") + "</span></div></div>"

 def sec(t, items):
  if not items: return ""
  h = "<div class=\"sec\"><h2>" + t + "</h2></div><div class=\"grid\">"
  for x in sorted(items, key=lambda x: (-x["stock"], x["marque"])):
   h += card(x)
  return h + "</div>"

 al = ""
 for p in rupt: al += "<div class=\"alert alert-rup\">Rupture: <strong>" + p["marque"] + " " + p["nom"] + "</strong></div>"
 for p in low: al += "<div class=\"alert alert-bas\">Stock bas: <strong>" + p["marque"] + " " + p["nom"] + "</strong> (" + str(p["stock"]) + " restants)</div>"

 now = datetime.datetime.now()
 html = "<!DOCTYPE html><html lang=\"fr\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1.0\"><title>Collection Privee - Parfums</title>"
 html += "<link href=\"https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=Inter:wght@300;400;500;600&display=swap\" rel=\"stylesheet\">"
 html += "<style>*{margin:0;padding:0;box-sizing:border-box;}body{font-family:Inter,sans-serif;background:#0a0a0f;color:#e8e0d4;}.header{background:linear-gradient(135deg,#1a1a2e,#16213e,#0f3460);padding:40px 0;text-align:center;border-bottom:1px solid rgba(212,175,55,0.2);}.header h1{font-family:Playfair Display,serif;font-size:2.8em;color:#d4af37;letter-spacing:4px;}.header .sub{font-size:.9em;color:#a0998e;margin-top:8px;letter-spacing:6px;text-transform:uppercase;}.stats{display:flex;justify-content:center;gap:40px;padding:20px;background:rgba(26,26,46,0.8);border-bottom:1px solid rgba(212,175,55,0.1);}.s-item{text-align:center;}.s-val{font-family:Playfair Display,serif;font-size:1.8em;color:#d4af37;font-weight:700;}.s-lbl{font-size:.75em;color:#6b6360;text-transform:uppercase;letter-spacing:2px;}.s-rup .s-val{color:#ff4757;}.s-bas .s-val{color:#ffa502;}.alerts{max-width:1200px;margin:20px auto;padding:0 20px;}.alert{padding:12px 20px;border-radius:8px;margin-bottom:8px;font-size:.9em;}.alert-rup{background:rgba(255,71,87,0.1);border:1px solid rgba(255,71,87,0.3);color:#ff6b81;}.alert-bas{background:rgba(255,165,2,0.1);border:1px solid rgba(255,165,2,0.3);color:#ffa502;}.sec{max-width:1200px;margin:30px auto 15px;padding:0 20px;}.sec h2{font-family:Playfair Display,serif;font-size:1.5em;color:#d4af37;border-bottom:1px solid rgba(212,175,55,0.2);padding-bottom:8px;}.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:16px;max-width:1200px;margin:0 auto;padding:0 20px 40px;}.c{background:linear-gradient(145deg,#1a1a2e,#16213e);border:1px solid rgba(212,175,55,0.15);border-radius:12px;padding:20px;transition:all .3s;position:relative;}.c:hover{transform:translateY(-4px);border-color:rgba(212,175,55,0.4);box-shadow:0 8px 30px rgba(212,175,55,0.1);}.c.rup{opacity:.6;border-color:rgba(255,71,87,0.3);}.c-bdg{position:absolute;top:12px;right:12px;}.bdg{font-size:.7em;padding:3px 8px;border-radius:20px;font-weight:600;}.bdg-rup{background:rgba(255,71,87,0.15);color:#ff4757;border:1px solid rgba(255,71,87,0.3);}.bdg-bas{background:rgba(255,165,2,0.15);color:#ffa502;border:1px solid rgba(255,165,2,0.3);}.bdg-ok{background:rgba(46,213,115,0.15);color:#2ed573;border:1px solid rgba(46,213,115,0.3);}.c-hd{display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;}.mq{font-size:.75em;color:#d4af37;text-transform:uppercase;letter-spacing:2px;font-weight:600;}.tp{font-size:.7em;color:#6b6360;}.c-tl{font-family:Playfair Display,serif;font-size:1.3em;color:#e8e0d4;margin-bottom:6px;}.c-nt{font-size:.8em;color:#8a8278;margin-bottom:12px;}.c-ft{display:flex;justify-content:space-between;border-top:1px solid rgba(212,175,55,0.1);padding-top:12px;}.pr{font-family:Playfair Display,serif;font-size:1.1em;color:#d4af37;}.st{font-size:.85em;color:#6b6360;}@media print{body{background:white;color:#222;}.header{background:#f5f0eb!important}.header h1{color:#1a1a2e!important}.c{background:#fafafa!important;border-color:#ddd!important;break-inside:avoid}.mq,.pr,.sec h2{color:#1a1a2e!important}.stats{background:#f0ece8!important}}@media(max-width:640px){.header h1{font-size:1.8em}.grid{grid-template-columns:1fr}}</style></head><body>"
 html += "<div class=\"header\"><h1>&#10022; COLLECTION PRIVEE &#10022;</h1><div class=\"sub\">Parfumerie de Luxe - Catalogue</div></div>"
 html += "<div class=\"stats\"><div class=\"s-item\"><div class=\"s-val\">" + str(len(P)) + "</div><div class=\"s-lbl\">Parfums</div></div>"
 html += "<div class=\"s-item\"><div class=\"s-val\">" + str(total) + "</div><div class=\"s-lbl\">Unites en stock</div></div>"
 html += "<div class=\"s-item" + (" s-rup" if rupt else "") + "\"><div class=\"s-val\">" + str(len(rupt)) + "</div><div class=\"s-lbl\">Ruptures</div></div>"
 html += "<div class=\"s-item" + (" s-bas" if low else "") + "\"><div class=\"s-val\">" + str(len(low)) + "</div><div class=\"s-lbl\">Stock bas</div></div></div>"
 html += "<div class=\"alerts\">" + al + "</div>"
 html += sec("HOMME", [p for p in P if p["categorie"] == "Homme"])
 html += sec("FEMME", [p for p in P if p["categorie"] == "Femme"])
 html += sec("MIXTES / UNISEX", [p for p in P if p["categorie"] == "Mixte"])
 html += "<div style=\"text-align:center;padding:20px;color:#6b6360;font-size:.8em;\">Genere automatiquement<br>Derniere MAJ: " + now.strftime("%d/%m/%Y %H:%M") + "</div></body></html>"

 hp = os.path.join(D, "catalogue.html")
 with open(hp, "w", encoding="utf-8") as f: f.write(html)
 print("Catalogue: " + hp)
 gen_img()



