 f2="@collection.privee"
 b5=draw.textbbox((0,0),f2,font=fb); draw.text(((W-(b5[2]-b5[0]))//2,fy+54),f2,fill="#d4af37",font=fb)
 hp=os.path.join(D,"whatsapp-status.jpg"); img.save(hp,"JPEG",quality=97)
