if __name__ == "__main__":
 import argparse
 a = argparse.ArgumentParser()
 a.add_argument("--set", nargs=2)
 a.add_argument("--add", nargs=2)
 a.add_argument("--nouveau", type=str)
 args = a.parse_args()
 if args.set: set_stock(args.set[0], int(args.set[1]))
 elif args.add: add_stock(args.add[0], int(args.add[1]))
 elif args.nouveau:
  import json as j
  try: add_new(j.loads(args.nouveau))
  except Exception as e: print("JSON invalide: " + str(e))
 else:
  d = L(); A(d); gen()
